#!/usr/bin/env bash
# evidence.sh — Evidence 决策助手 for AIGC 创作工作流.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AIGC 创作工作流"
TOPIC="Evidence"

usage() {
  cat <<EOF
evidence.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 5 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./evidence.sh             # interactive
  ./evidence.sh --dry-run   # walk through but no file
  ./evidence.sh --json      # JSON to stdout
  ./evidence.sh --explain   # show backing playbook rules + mental models
  ./evidence.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Evidence 主题下的 playbook 规则组合成交互树。

基于 5 条规则:
  • 如果 出图质量不达标 → 则 先查 prompt / 控制链 / 放大链再考虑换底模，别指望「换个更大的底模解决一切」。案例：弱 prompt 下 3
  • 如果 要让生成遵循指定构图/姿态/线稿 → 则 上 ControlNet 按「要锁什么」选预处理器（姿态用 OpenPose、空间用 Depth、边缘用 Canny），
  • 如果 需要角色/风格跨多图一致 → 则 先问「长期 IP 还是一次性」——一次性走免训练（IPAdapter/InstantID/Midjourney Omni
  • 如果 换底模 → 则 ControlNet/LoRA/IPAdapter 必须换配对代际，否则静默失效。案例：SDXL 的 LoRA/Cont
  • 如果 交付物要可回溯/改稿 → 则 开源链锁 seed + 存全参数 + 导 workflow JSON，闭源链（Midjourney/可灵不可锁种子）建参

相关心智模型:
  • 可控性 ⇄ 抽卡随机（slot machine）的第一性张力: 扩散模型本质是「抽卡机」（Bilawal Sidhu 直接命名 slot machine nature），同 prompt 多跑挑可用——生成式视觉创作的每个决策都在「可控性/工程化复现 ⇄ 随机性/
  • 模型是地板，审美与判断是天花板: 同样的模型与参数，产出天差地别取决于人的审美判断、概念、构图、镜头语言与「在哪一步停」的判断；模型决定下限（地板），人的审美与工程判断决定上限（天花板），「换个更大的底模就行」是外行幻觉。

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "出图质量不达标"
  "要让生成遵循指定构图/姿态/线稿"
  "需要角色/风格跨多图一致"
  "换底模"
  "交付物要可回溯/改稿"
)
declare -a RULE_ACTIONS=(
  "先查 prompt / 控制链 / 放大链再考虑换底模，别指望「换个更大的底模解决一切」。案例：弱 prompt 下 32B 的 Flux.2（官方参数）不一定胜过调好的 SDXL 工作流（T02-S002）。evidence: [T02-S001, T02-S002]"
  "上 ControlNet 按「要锁什么」选预处理器（姿态用 OpenPose、空间用 Depth、边缘用 Canny），别只靠文生图堆词。案例：锁人物动作用 OpenPose，保产品轮廓换背景用 Canny（T03-S005）。evidence: [T06-S005, T03-S005]"
  "先问「长期 IP 还是一次性」——一次性走免训练（IPAdapter/InstantID/Midjourney Omni Reference），长期/批产才训 LoRA。案例：单角色短期需求 IPAdapter 几分钟搞定，不必花半天训 LoRA（T03-S011）。evidence: [T02-S012, T03-S011]"
  "ControlNet/LoRA/IPAdapter 必须换配对代际，否则静默失效。案例：SDXL 的 LoRA/ControlNet 套到 Flux 底模无效或报错（T02-S011）。evidence: [T02-S011, T02-S020]"
  "开源链锁 seed + 存全参数 + 导 workflow JSON，闭源链（Midjourney/可灵不可锁种子）建参数台账。案例：ComfyUI 用 PNG 内嵌工作流元数据可复现（T03-S003）。evidence: [T03-S003, T06-S003]"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "evidence-decision"
fi
